-- ============================================================
-- SOVEREIGN GENESIS EVENT — MARKETPLACE BOOTSTRAP
-- Generated: GENESIS_EVENT_2026
-- Architect: 50529956
-- Population: 100 ancestors
-- ============================================================

CREATE TABLE IF NOT EXISTS genesis_entities (
  id SERIAL PRIMARY KEY,
  entity_index INTEGER NOT NULL,
  entity_hash VARCHAR(64) NOT NULL UNIQUE,
  entity_key VARCHAR(32) NOT NULL UNIQUE,
  rarity VARCHAR(16) NOT NULL,
  phenotype_class VARCHAR(32) NOT NULL,
  mesh_family VARCHAR(32) NOT NULL,
  generation INTEGER NOT NULL DEFAULT 0,
  origin VARCHAR(64) NOT NULL DEFAULT 'GENESIS_EVENT_2026',
  architect VARCHAR(32) NOT NULL DEFAULT '50529956',
  genome_hex VARCHAR(64) NOT NULL,
  pedigree_hash VARCHAR(64) NOT NULL,
  claim_status VARCHAR(16) NOT NULL DEFAULT 'UNCLAIMED',
  claimed_by VARCHAR(64) DEFAULT NULL,
  claimed_at TIMESTAMP DEFAULT NULL,
  integrity_verified BOOLEAN NOT NULL DEFAULT TRUE,
  created_at TIMESTAMP NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_genesis_rarity ON genesis_entities(rarity);
CREATE INDEX IF NOT EXISTS idx_genesis_class ON genesis_entities(phenotype_class);
CREATE INDEX IF NOT EXISTS idx_genesis_status ON genesis_entities(claim_status);

ON CONFLICT (entity_hash) DO NOTHING;
